/**
 * Get DAT Analytics for the Progress Page
 */
export const getDatAnalytics = catchAsync(async (req: Request, res: Response) => {
  const analytics = await datService.getDatAnalytics((req as any).user);
  res.statusSuccess(analytics, 'DAT Analytics retrieved successfully');
});

/**
 * Add a new DAT Session
 */
export const addDatSession = catchAsync(async (req: Request, res: Response) => {
  const session = await datService.addDatSession(req.body);
  res.statusSuccess(session, 'DAT Session added successfully');
});

/**
 * Get DAT Sessions for a specific enrollment
 */
export const getStudentDatSessions = catchAsync(async (req: Request, res: Response) => {
  const { enrollmentId } = req.params;
  const sessions = await datService.getStudentDatSessions(enrollmentId as string);
  res.statusSuccess(sessions, 'Student DAT sessions retrieved successfully');
});

